CREATE TYPE document_type_enum AS ENUM ('invoice', 'quote', 'order', 'payment', 'miscellaneous', 'appointment');
CREATE TYPE reset_period_enum AS ENUM ('never', 'daily', 'weekly', 'monthly', 'yearly');
CREATE TYPE recurrence_type AS ENUM ('daily', 'weekly', 'biweekly', 'monthly', 'yearly', 'none');

            CREATE OR REPLACE FUNCTION public.get_user_primary_type(
	p_user_id uuid)
    RETURNS text
    LANGUAGE 'plpgsql'
    COST 100
    STABLE PARALLEL UNSAFE
AS $BODY$
DECLARE
    v_is_sales BOOLEAN;
BEGIN
    -- Obtener is_sales del usuario
    SELECT is_sales INTO v_is_sales FROM users WHERE id = p_user_id;

    -- Priorizar roles específicos
    IF user_has_role(p_user_id, 'employee') THEN
        RETURN 'employee';
    ELSIF user_has_role(p_user_id, 'owner') THEN
        RETURN 'owner';
    ELSIF user_has_role(p_user_id, 'government') THEN
        RETURN 'government';
    ELSIF user_has_role(p_user_id, 'other_party') THEN
        RETURN 'other';
    -- Si no tiene roles específicos, usar is_sales
    ELSIF v_is_sales = true THEN
        RETURN 'customer';
    ELSIF v_is_sales = false THEN
        RETURN 'supplier';
    ELSE
        RETURN 'other';
    END IF;
END;
$BODY$;
